# PRODUCT
class Transport:
    def deliver(self): pass

# CONCRETE PRODUCTS
class Truck(Transport):
    def deliver(self): print("Truck delivery")

class Ship(Transport):
    def deliver(self): print("Ship delivery")

# CREATOR
class Logistics:
    def create_transport(self) -> Transport: pass
    def deliver_order(self):
        transport = self.create_transport()
        transport.deliver()

# CONCRETE CREATORS
class RoadLogistics(Logistics):
    def create_transport(self): return Truck()

class SeaLogistics(Logistics):
    def create_transport(self): return Ship()

